import{_ as a,o as l,c as i,ag as o}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Dotfiles Hakkında | Dotfiles (TR)","titleTemplate":":title","description":"Keşfedin dotfiles v0.2.495 teknik genel bakış. macOS, Linux ve WSL ile Dotfiles üzerinden uyumlu.","frontmatter":{"title":"Dotfiles Hakkında | Dotfiles","description":"Keşfedin dotfiles v0.2.495 teknik genel bakış. macOS, Linux ve WSL ile Dotfiles üzerinden uyumlu.","lang":"tr-TR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Dotfiles Hakkında | Dotfiles önizleme","canonical":"/tr/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Hakkında","pageType":"docs","schemaType":"WebPage","permalink":"/tr/about/"},"headers":[],"relativePath":"tr/about/index.md","filePath":"tr/about/index.md","lastUpdated":1773010926000}'),r={name:"tr/about/index.md"};function t(d,e,n,s,c,u){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="dotfiles-hakkında" tabindex="-1">Dotfiles Hakkında <a class="header-anchor" href="#dotfiles-hakkında" aria-label="Permalink to &quot;Dotfiles Hakkında&quot;">​</a></h1><p>Dotfiles v0.2.495, Chezmoi tarafından yönetilen çapraz platform kabuk yapılandırmasıdır.</p><h2 id="kurulum" tabindex="-1">Kurulum <a class="header-anchor" href="#kurulum" aria-label="Permalink to &quot;Kurulum&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="dogrulama" tabindex="-1">Doğrulama <a class="header-anchor" href="#dogrulama" aria-label="Permalink to &quot;Doğrulama&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="temel-komutlar" tabindex="-1">Temel Komutlar <a class="header-anchor" href="#temel-komutlar" aria-label="Permalink to &quot;Temel Komutlar&quot;">​</a></h2><ul><li><code>dot apply</code> yapılandırma değişikliklerini uygular.</li><li><code>dot update</code> depoyu günceller ve önbellekleri ısıtır.</li><li><code>dot doctor</code> yolları, araçları ve kabuk sağlığını doğrular.</li><li><code>dot heal</code> eksik veya bozuk durumu onarır.</li><li><code>dot smoke-test</code> temel araç zincirlerini doğrular.</li></ul><h2 id="ilgili" tabindex="-1">İlgili <a class="header-anchor" href="#ilgili" aria-label="Permalink to &quot;İlgili&quot;">​</a></h2><ul><li><a href="/tr/aliases/">Takma adlar</a></li><li><a href="/tr/functions/">Fonksiyonlar</a></li><li><a href="/tr/paths/">Yollar</a></li><li><a href="/tr/compatibility/">Uyumluluk matrisi</a></li></ul><h2 id="temel-komutlar-1" tabindex="-1">Temel komutlar <a class="header-anchor" href="#temel-komutlar-1" aria-label="Permalink to &quot;Temel komutlar&quot;">​</a></h2><p><code>dot</code> CLI, kategorilere göre düzenlenmiş 53 komut sunar.</p><h3 id="cekirdek" tabindex="-1">Çekirdek <a class="header-anchor" href="#cekirdek" aria-label="Permalink to &quot;Çekirdek&quot;">​</a></h3><ul><li><code>dot apply</code> — yapılandırma değişikliklerini uygular.</li><li><code>dot sync</code> — en son repo durumunu çeker ve uygular.</li><li><code>dot update</code> — repoyu günceller ve önbellekleri ısıtır.</li><li><code>dot add</code> — Chezmoi kaynağına yeni dosyalar ekler.</li><li><code>dot diff</code> — uygulamadan önce bekleyen değişiklikleri gösterir.</li><li><code>dot status</code> — yönetilen dosyaların durumunu görüntüler.</li><li><code>dot remove</code> — bir dosyayı yönetimden çıkarır ve kaynak kaydını siler.</li><li><code>dot cd</code> — Chezmoi kaynak dizininde bir shell açar.</li><li><code>dot edit</code> — yönetilen bir dosyayı düzenleyicinizde açar.</li><li><code>dot clean-cache</code> — geçici önbellekleri temizler.</li><li><code>dot prewarm</code> — daha hızlı shell başlatma için önbellekleri önceden doldurur.</li></ul><h3 id="tanılama" tabindex="-1">Tanılama <a class="header-anchor" href="#tanılama" aria-label="Permalink to &quot;Tanılama&quot;">​</a></h3><ul><li><code>dot doctor</code> — yolları, araçları ve shell durumunu doğrular.</li><li><code>dot heal</code> — eksik veya bozuk durumu otomatik olarak onarır.</li><li><code>dot health</code> — hafif bir sağlık kontrolü çalıştırır.</li><li><code>dot verify</code> — dosya bütünlüğünü kaynağa göre kontrol eder.</li><li><code>dot scorecard</code> — yapılandırma kalite puanını yazdırır.</li><li><code>dot snapshot</code> — sonraki karşılaştırma için mevcut durumu yakalar.</li><li><code>dot smoke-test</code> — temel araç zincirlerini uçtan uca doğrular.</li><li><code>dot chaos</code> — kendi kendini onarımı test etmek için hatalar enjekte eder.</li><li><code>dot bundle</code> — taşınabilir bir yapılandırma paketi dışa aktarır.</li><li><code>dot rollback</code> — önceki bir anlık görüntüye geri döner.</li><li><code>dot drift</code> — yönetilen dosyalardaki beklenmeyen değişiklikleri algılar.</li><li><code>dot history</code> — apply/sync geçmiş günlüğünü gösterir.</li><li><code>dot benchmark</code> — shell başlatma süresini ölçer.</li><li><code>dot perf</code> — yavaş shell başlatmayı profiller.</li></ul><h3 id="gorunum" tabindex="-1">Görünüm <a class="header-anchor" href="#gorunum" aria-label="Permalink to &quot;Görünüm&quot;">​</a></h3><ul><li><code>dot theme</code> — terminal renk şemasını değiştirir.</li><li><code>dot wallpaper</code> — masaüstü duvar kağıdını ayarlar (macOS).</li><li><code>dot fonts</code> — Nerd Fonts&#39;u yükler veya günceller.</li><li><code>dot tune</code> — arayüz yoğunluğunu ve komut istemi stilini ayarlar.</li></ul><h3 id="guvenlik" tabindex="-1">Güvenlik <a class="header-anchor" href="#guvenlik" aria-label="Permalink to &quot;Güvenlik&quot;">​</a></h3><ul><li><code>dot backup</code> — şifrelenmiş yapılandırma yedekleri oluşturur.</li><li><code>dot encrypt-check</code> — durağan haldeki gizli anahtar şifrelemesini doğrular.</li><li><code>dot firewall</code> — ana bilgisayar güvenlik duvarı kurallarını yapılandırır.</li><li><code>dot telemetry</code> — anonim kullanım telemetrisini kontrol eder.</li><li><code>dot dns-doh</code> — DNS-over-HTTPS&#39;yi etkinleştirir.</li><li><code>dot lock-screen</code> — ekranı hemen kilitler.</li><li><code>dot usb-safety</code> — USB yığın depolama otomatik bağlamayı kısıtlar.</li></ul><h3 id="gizli-anahtarlar" tabindex="-1">Gizli anahtarlar <a class="header-anchor" href="#gizli-anahtarlar" aria-label="Permalink to &quot;Gizli anahtarlar&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — gizli anahtar arka ucunu başlatır (age / GPG).</li><li><code>dot secrets</code> — şifrelenmiş gizli anahtar girdilerini listeler.</li><li><code>dot secrets-create</code> — yeni şifrelenmiş bir gizli anahtar oluşturur.</li><li><code>dot ssh-key</code> — SSH anahtar çiftleri oluşturur veya döndürür.</li><li><code>dot ssh-cert</code> — bir CA&#39;dan SSH sertifikası talep eder.</li></ul><h3 id="yapay-zeka" tabindex="-1">Yapay Zeka <a class="header-anchor" href="#yapay-zeka" aria-label="Permalink to &quot;Yapay Zeka&quot;">​</a></h3><ul><li><code>dot ai</code> — etkileşimli bir yapay zeka asistanı oturumu açar.</li><li><code>dot ai-setup</code> — yapay zeka sağlayıcıları için API anahtarlarını yapılandırır.</li><li><code>dot ai-query</code> — bir yapay zeka modeline tek seferlik istem gönderir.</li><li>Yapay zeka araç sarmalayıcıları: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="araclar" tabindex="-1">Araçlar <a class="header-anchor" href="#araclar" aria-label="Permalink to &quot;Araçlar&quot;">​</a></h3><ul><li><code>dot tools</code> — paketlenmiş CLI alternatiflerini ve durumlarını listeler.</li><li><code>dot new</code> — yeni bir takma ad veya fonksiyon dosyası oluşturur.</li><li><code>dot sandbox</code> — tek kullanımlık bir sandbox shell açar.</li><li><code>dot keys</code> — mevcut tuş atamalarını gösterir.</li><li><code>dot learn</code> — etkileşimli öğreticiyi başlatır.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — Dotfiles&#39;ı en son sürüme yükseltir.</li><li><code>dot packages</code> — Dotfiles tarafından yönetilen yüklü paketleri listeler.</li><li><code>dot version</code> / <code>dot help</code> — sürüm veya kullanım bilgilerini yazdırır</li></ul>',28)])])}const m=a(r,[["render",t]]);export{h as __pageData,m as default};
